import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder sb = new StringBuilder();
        while (fs.hasNext()) {
            int g = fs.nextInt();
            int s = fs.nextInt();
            int b = fs.nextInt();
            int need = 0;
            if (g < 5) need += 5 - g;
            if (s < 5) need += 5 - s;
            if (b < 5) need += 5 - b;
            sb.append(need).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Simple fast scanner
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        boolean hasNext() throws IOException {
            int c;
            while ((c = readByte()) != -1) {
                if (!Character.isWhitespace(c)) { ptr--; return true; }
            }
            return false;
        }
        int nextInt() throws IOException {
            int c = readByte();
            while (c <= ' ') c = readByte();
            int sign = 1;
            if (c == '-') { sign = -1; c = readByte(); }
            int val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

