#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    out_lines = []
    for i in range(0, len(data), 3):
        g, s, b = data[i], data[i+1], data[i+2]
        need = 0
        if g < 5:
            need += 5 - g
        if s < 5:
            need += 5 - s
        if b < 5:
            need += 5 - b
        out_lines.append(str(need))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

